<?php
$search=trim((string)($_GET['q']??'')); $status=(string)($_GET['status']??''); $currency=(string)($_GET['currency']??''); $where=' WHERE 1=1'; $params=[];
if($search!==''){ $where.=' AND (c.name LIKE ? OR p.description LIKE ? OR p.external_reference LIKE ?)'; $like='%'.$search.'%';$params=[$like,$like,$like]; }
if(in_array($status,['pending','paid','failed','refunded'],true)){ $where.=' AND p.status=?';$params[]=$status; }
if(in_array($currency,['BRL','USD'],true)){ $where.=' AND p.currency=?';$params[]=$currency; }
$pagination=pagination($db,'SELECT COUNT(*) FROM payments p JOIN clients c ON c.id=p.client_id'.$where,'SELECT p.*,c.name client FROM payments p JOIN clients c ON c.id=p.client_id'.$where.' ORDER BY COALESCE(p.payment_date,p.due_date) DESC,p.id DESC',$params);
$edit=isset($_GET['edit'])?$db->fetch('SELECT * FROM payments WHERE id=?',[(int)$_GET['edit']]):null; $showForm=isset($_GET['new'])||$edit;
$clients=$showForm?$db->fetchAll("SELECT id,name,preferred_currency FROM clients WHERE status!='inactive' OR id=? ORDER BY name",[(int)($edit['client_id']??0)]):[];
$subscriptions=$showForm?$db->fetchAll("SELECT s.id,s.client_id,s.currency,s.unit_price,s.quantity,s.discount,c.name client,p.name product FROM subscriptions s JOIN clients c ON c.id=s.client_id JOIN products p ON p.id=s.product_id WHERE s.status!='canceled' OR s.id=? ORDER BY c.name,p.name",[(int)($edit['subscription_id']??0)]):[];
$currentRate=$showForm?$rates->current():null;
[$rangeFrom,$rangeTo]=period_dates();
$paymentTotals=$db->fetch("SELECT COALESCE(SUM(CASE WHEN status='paid' THEN amount_brl ELSE 0 END),0) paid,COALESCE(SUM(CASE WHEN status='pending' THEN amount_brl ELSE 0 END),0) pending,COALESCE(SUM(CASE WHEN status='paid' THEN fee_brl ELSE 0 END),0) fees FROM payments WHERE COALESCE(payment_date,due_date) BETWEEN ? AND ?",[$rangeFrom,$rangeTo]);
?>
<section class="mini-stats money-stats"><div><span class="dot green"></span><span><small>Recebido no mês</small><b><?= money($paymentTotals['paid']) ?></b></span></div><div><span class="dot gold"></span><span><small>Pendente no mês</small><b><?= money($paymentTotals['pending']) ?></b></span></div><div><span class="dot red"></span><span><small>Taxas no mês</small><b><?= money($paymentTotals['fees']) ?></b></span></div></section>
<section class="toolbar list-toolbar"><form class="search-filters" method="get"><input type="hidden" name="page" value="payments"><label class="search-box">⌕<input name="q" placeholder="Cliente, descrição ou referência" value="<?= h($search) ?>"></label><select name="currency"><option value="">BRL + USD</option><option value="BRL" <?= $currency==='BRL'?'selected':'' ?>>BRL</option><option value="USD" <?= $currency==='USD'?'selected':'' ?>>USD</option></select><select name="status"><option value="">Todos os status</option><option value="paid" <?= $status==='paid'?'selected':'' ?>>Pagos</option><option value="pending" <?= $status==='pending'?'selected':'' ?>>Pendentes</option><option value="failed" <?= $status==='failed'?'selected':'' ?>>Falhos</option><option value="refunded" <?= $status==='refunded'?'selected':'' ?>>Estornados</option></select><button class="button secondary">Filtrar</button></form><div><a class="button ghost" href="?page=export&type=payments">⇩ Exportar</a><?php if($auth->canWrite()): ?><a class="button primary" href="?page=payments&new=1">＋ Novo pagamento</a><?php endif; ?></div></section>
<section class="card table-card"><div class="table-meta"><span><b><?= $pagination['total'] ?></b> pagamentos</span></div><div class="table-wrap"><table><thead><tr><th>Pagamento</th><th>Data</th><th>Valor original</th><th>Cotação usada</th><th>Líquido em BRL</th><th>Status</th><th></th></tr></thead><tbody>
<?php if(!$pagination['rows']): ?><tr><td colspan="7" class="empty-cell">Nenhum pagamento encontrado.</td></tr><?php endif; ?>
<?php foreach($pagination['rows'] as $item): ?><tr><td><div class="entity"><span class="avatar-sm"><?= h(mb_strtoupper(mb_substr($item['client'],0,1))) ?></span><span><b><?= h($item['client']) ?></b><small><?= h($item['description']?:$item['external_reference']?:'Pagamento') ?></small></span></div></td><td><?= date_br($item['payment_date']?:$item['due_date']) ?></td><td><b><?= money($item['amount'],$item['currency']) ?></b><?php if($item['fee_amount']>0): ?><small class="block">Taxa: <?= money($item['fee_amount'],$item['currency']) ?></small><?php endif; ?></td><td><?= $item['currency']==='USD'?'R$ '.number_format($item['exchange_rate'],4,',','.'):'—' ?></td><td><b><?= money($item['net_brl']) ?></b></td><td><span class="badge <?= status_class($item['status']) ?>"><?= status_label($item['status']) ?></span></td><td><a class="row-action" href="?page=payments&edit=<?= (int)$item['id'] ?>">•••</a></td></tr><?php endforeach; ?>
</tbody></table></div><?= render_pagination($pagination) ?></section>
<?php if($showForm): ?><div class="modal open"><a class="modal-backdrop" href="?page=payments"></a><section class="modal-panel wide"><header><div><p class="eyebrow">RECEBIMENTOS</p><h2><?= $edit?'Editar pagamento':'Novo pagamento' ?></h2></div><a href="?page=payments" class="modal-close">×</a></header><form method="post" class="form-grid" data-money-form data-current-rate="<?= h($currentRate['bid']) ?>"><?= csrf_field() ?><input type="hidden" name="action" value="save_payment"><input type="hidden" name="id" value="<?= (int)($edit['id']??0) ?>"><input type="hidden" name="_return" value="<?= h($_SERVER['REQUEST_URI']) ?>">
<label>Cliente<select name="client_id" required data-payment-client><option value="">Selecione…</option><?php foreach($clients as $client): ?><option value="<?= (int)$client['id'] ?>" data-currency="<?= h($client['preferred_currency']) ?>" <?= (int)($edit['client_id']??0)===(int)$client['id']?'selected':'' ?>><?= h($client['name']) ?></option><?php endforeach; ?></select></label><label>Assinatura (opcional)<select name="subscription_id" data-payment-sub><option value="">Pagamento avulso</option><?php foreach($subscriptions as $sub): $subValue=max(0,$sub['unit_price']*$sub['quantity']-$sub['discount']); ?><option value="<?= (int)$sub['id'] ?>" data-client="<?= (int)$sub['client_id'] ?>" data-currency="<?= h($sub['currency']) ?>" data-amount="<?= h($subValue) ?>" <?= (int)($edit['subscription_id']??0)===(int)$sub['id']?'selected':'' ?>><?= h($sub['client'].' · '.$sub['product']) ?></option><?php endforeach; ?></select></label><label class="span-2">Descrição<input name="description" value="<?= h($edit['description']??'') ?>" placeholder="Ex.: Mensalidade de julho"></label><label>Moeda<select name="currency" data-money-currency><option value="BRL" <?= ($edit['currency']??'BRL')==='BRL'?'selected':'' ?>>BRL — Real</option><option value="USD" <?= ($edit['currency']??'')==='USD'?'selected':'' ?>>USD — Dólar</option></select></label><label>Valor recebido<input name="amount" type="number" step="0.01" min="0.01" required data-money-amount value="<?= decimal_input($edit['amount']??0) ?>"></label><label>Taxa da plataforma (na mesma moeda)<input name="fee_amount" type="number" step="0.01" min="0" data-money-fee value="<?= decimal_input($edit['fee_amount']??0) ?>"></label><label>Cotação USD → BRL<input name="exchange_rate" type="number" step="0.000001" min="0" data-money-rate value="<?= h($edit['exchange_rate']??$currentRate['bid']) ?>"><small data-rate-help><?= $edit?'Cotação histórica salva neste pagamento':'Cotação atual via AwesomeAPI' ?></small></label><div class="conversion-preview span-2"><span>Valor líquido convertido</span><strong data-money-preview>R$ 0,00</strong><small>A cotação ficará registrada neste pagamento e não mudará depois.</small></div><label>Status<select name="status"><option value="paid" <?= ($edit['status']??'paid')==='paid'?'selected':'' ?>>Pago</option><option value="pending" <?= ($edit['status']??'')==='pending'?'selected':'' ?>>Pendente</option><option value="failed" <?= ($edit['status']??'')==='failed'?'selected':'' ?>>Falhou</option><option value="refunded" <?= ($edit['status']??'')==='refunded'?'selected':'' ?>>Estornado</option></select></label><label>Forma de pagamento<input name="payment_method" value="<?= h($edit['payment_method']??'') ?>" placeholder="Stripe, PIX, cartão…"></label><label>Vencimento<input name="due_date" type="date" value="<?= h($edit['due_date']??date('Y-m-d')) ?>"></label><label>Data do pagamento<input name="payment_date" type="date" value="<?= h($edit['payment_date']??date('Y-m-d')) ?>"></label><label class="span-2">Referência externa<input name="external_reference" value="<?= h($edit['external_reference']??'') ?>" placeholder="ID do Stripe, banco ou nota fiscal"></label><label class="span-2">Observações<textarea name="notes" rows="3"><?= h($edit['notes']??'') ?></textarea></label><footer class="span-2"><a class="button ghost" href="?page=payments">Cancelar</a><button class="button primary">Salvar pagamento</button></footer></form><?php if($edit&&$auth->canWrite()): ?><form method="post" class="danger-zone" data-confirm="Excluir este pagamento? O dashboard será recalculado."><?= csrf_field() ?><input type="hidden" name="action" value="delete_payment"><input type="hidden" name="id" value="<?= (int)$edit['id'] ?>"><button>Excluir pagamento</button></form><?php endif; ?></section></div><?php endif; ?>

